   193→            logger.LogInformation(
   194→                "Computed Focus-Time Ratio KPI. Focus: {Focus}h, Meeting: {Meeting}h, Ratio: {Ratio:p2}",
   195→                focusDuration.TotalHours,
   196→                meetingDuration.TotalHours,
   197→                ratio);
