   199→            var metadata = new Dictionary<string, object>
   200→            {
   201→                ["focusHours"]   = Math.Round(focusDuration.TotalHours,   2),
   202→                ["meetingHours"] = Math.Round(meetingDuration.TotalHours, 2),
   203→                ["version"]      = "v1.0.0"
