   432→    /// <summary>
   433→    /// Declarative, exponential back-off retry wrapper for S3 operations.
   434→    /// </summary>
   435→    internal sealed class AmazonS3RetryPolicy
   436→    {
   437→        private static readonly TimeSpan[] BackOffSchedule =
   438→        {
   439→            TimeSpan.FromMilliseconds(100),
   440→            TimeSpan.FromMilliseconds(250),
   441→            TimeSpan.FromMilliseconds(500),
   442→            TimeSpan.FromSeconds(1),
   443→            TimeSpan.FromSeconds(2)
   444→        };
   445→
   446→        public async Task ExecuteAsync(Func<Task> operation, CancellationToken ct)
   447→        {
   448→            var attempt = 0;
   449→            Exception? lastError = null;
   450→
   451→            foreach (var delay in BackOffSchedule.Append(TimeSpan.Zero))
   452→            {
   453→                try
   454→                {
   455→                    ct.ThrowIfCancellationRequested();
   456→                    await operation().ConfigureAwait(false);
   457→                    return; // success
   458→                }
   459→                catch (Exception ex) when (IsTransient(ex))
   460→                {
   461→                    lastError = ex;
   462→                    attempt++;
   463→                    if (delay > TimeSpan.Zero)
   464→                        await Task.Delay(delay, ct).ConfigureAwait(false);
   465→                }
   466→            }
   467→
   468→            throw new InvalidOperationException(
   469→                $"S3 operation failed after {attempt} retries.", lastError);
   470→        }
   471→
   472→        private static bool IsTransient(Exception ex)
   473→        {
   474→            // TODO: Add richer fault-analysis; for now assume all AmazonS3Exception with 5xx are transient.
