   109→    public sealed class TransformationCoordinator
   110→    {
   111→        private readonly IStrategyRegistry _registry;
   112→        private readonly ILogger<TransformationCoordinator> _logger;
   113→        private readonly IMetricsRecorder _metrics;
   114→        private readonly int _maxConcurrency;
   115→
   116→        public TransformationCoordinator(
   117→            IStrategyRegistry registry,
   118→            ILogger<TransformationCoordinator> logger,
   119→            IMetricsRecorder metrics,
   120→            int maxConcurrency = 8)
   121→        {
   122→            _registry = registry ?? throw new ArgumentNullException(nameof(registry));
   123→            _logger   = logger   ?? throw new ArgumentNullException(nameof(logger));
   124→            _metrics  = metrics  ?? throw new ArgumentNullException(nameof(metrics));
