   128→        /// <summary>
   129→        ///     Processes a batch of <paramref name="events"/> concurrently while
   130→        ///     respecting <see cref="_maxConcurrency"/>.
   131→        /// </summary>
   132→        public async Task HandleBatchAsync(
   133→            IReadOnlyCollection<StreamEvent> events,
   134→            CancellationToken token)
   135→        {
   136→            if (events is null) throw new ArgumentNullException(nameof(events));
   137→            if (events.Count == 0) return;
   138→
   139→            _logger.LogDebug("Starting batch transformation for {Count} events.", events.Count);
   140→
   141→            // Use a concurrent bag to capture failures for consolidated reporting
   142→            var failures = new ConcurrentBag<Exception>();
   143→
   144→            await Parallel.ForEachAsync(
   145→                events,
   146→                new ParallelOptions
   147→                {
   148→                    MaxDegreeOfParallelism = _maxConcurrency,
   149→                    CancellationToken      = token
   150→                },
   151→                async (@event, ct) =>
   152→                {
   153→                    try
   154→                    {
   155→                        await HandleSingleAsync(@event, ct).ConfigureAwait(false);
   156→                    }
   157→                    catch (Exception ex)
   158→                    {
   159→                        failures.Add(ex);
   160→                    }
   161→                }).ConfigureAwait(false);
   162→
   163→            if (!failures.IsEmpty)
   164→            {
   165→                _logger.LogError("{Count} events failed during transformation.", failures.Count);
   166→                throw new AggregateException("One or more events failed transformation.", failures);
   167→            }
   168→
   169→            _logger.LogInformation("Batch transformation completed successfully.");
   170→        }
