   172→        private async Task HandleSingleAsync(StreamEvent @event, CancellationToken ct)
   173→        {
   174→            var stopwatch = Stopwatch.StartNew();
   175→
   176→            if (!_registry.TryResolve<object?>(@event.StreamType, out var strategy))
   177→            {
   178→                _metrics.Increment("Transformation.UnknownStreamType", new Dictionary<string, string>
   179→                {
   180→                    ["StreamType"] = @event.StreamType
   181→                });
   182→
   183→                _logger.LogWarning(
   184→                    "Skipping event with unknown StreamType: {StreamType}.",
   185→                    @event.StreamType);
   186→
   187→                throw new StrategyNotFoundException(@event.StreamType);
   188→            }
   189→
   190→            try
   191→            {
   192→                var output = await strategy!.TransformAsync(@event, ct).ConfigureAwait(false);
   193→
   194→                // Downstream dispatch placeholder (e.g., to Firehose/Glue)
   195→                _logger.LogTrace(
   196→                    "Transformed event from {StreamType} into {OutputType}.",
   197→                    @event.StreamType, output?.GetType().Name ?? "<null>");
   198→
   199→                _metrics.Increment("Transformation.Success", new Dictionary<string, string>
   200→                {
   201→                    ["StreamType"] = @event.StreamType
   202→                });
   203→            }
   204→            catch (Exception ex)
   205→            {
   206→                _logger.LogError(ex,
   207→                    "Transformation failed for StreamType = {StreamType}.",
   208→                    @event.StreamType);
   209→
   210→                _metrics.Increment("Transformation.Failure", new Dictionary<string, string>
   211→                {
   212→                    ["StreamType"] = @event.StreamType
   213→                });
   214→
   215→                throw new DataTransformationException(
   216→                    $"Transformation failed for StreamType = {@event.StreamType}", ex);
   217→            }
   218→            finally
   219→            {
   220→                stopwatch.Stop();
   221→                _metrics.Timing("Transformation.Latency", stopwatch.Elapsed,
   222→                    new Dictionary<string, string> { ["StreamType"] = @event.StreamType });
   223→            }
   224→        }
   225→    }
