   231→    /// <summary>
   232→    ///     Thread-safe registry that supports hot-swapping strategies via DI.
   233→    /// </summary>
   234→    public sealed class StrategyRegistry : IStrategyRegistry
   235→    {
   236→        private readonly IReadOnlyDictionary<string, object> _map;
   237→
   238→        /// <summary>
   239→        ///     Instantiates the registry with an immutable map of streamType → strategy.
   240→        /// </summary>
   241→        public StrategyRegistry(IEnumerable<(string StreamType, object Strategy)> registrations)
   242→        {
   243→            if (registrations is null)
   244→                throw new ArgumentNullException(nameof(registrations));
   245→
   246→            var map = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
   247→            foreach (var (streamType, strategy) in registrations)
   248→            {
   249→                ArgumentNullException.ThrowIfNull(streamType);
   250→                ArgumentNullException.ThrowIfNull(strategy);
   251→
   252→                map[streamType] = strategy;
   253→            }
   254→
   255→            _map = map;
   256→        }
   257→
   258→        public bool TryResolve<TOut>(
   259→            string streamType,
   260→            [NotNullWhen(true)] out IDataTransformationStrategy<TOut>? strategy)
   261→        {
   262→            strategy = null;
   263→
   264→            if (_map.TryGetValue(streamType, out var obj) &&
   265→                obj is IDataTransformationStrategy<TOut> typed)
   266→            {
   267→                strategy = typed;
   268→                return true;
   269→            }
   270→
   271→            return false;
   272→        }
   273→    }
