   107→    /// <summary>
   108→    /// Default channel-backed event subject supporting multiple observers and graceful teardown.
   109→    /// </summary>
   110→    public sealed class ChannelEventSubject<T> : IEventSubject<T>, IDisposable
   111→    {
   112→        private readonly Channel<T> _channel;
   113→        private readonly IList<IEventObserver<T>> _observers = new List<IEventObserver<T>>();
   114→        private readonly CancellationTokenSource _internalCts = new();
   115→        private readonly Task _pumpTask;
   116→        private readonly ILogger _logger;
   117→
   118→        public ChannelEventSubject(int capacity, ILogger logger)
   119→        {
   120→            _logger = logger;
   121→            _channel = Channel.CreateBounded<T>(new BoundedChannelOptions(capacity)
   122→            {
   123→                FullMode = BoundedChannelFullMode.Wait,
   124→                SingleWriter = false,
   125→                SingleReader = true
   126→            });
   127→
   128→            _pumpTask = Task.Run(() => PumpAsync(_internalCts.Token), _internalCts.Token);
   129→        }
   130→
   131→        public void Attach(IEventObserver<T> observer) => _observers.Add(observer);
   132→
   133→        public async ValueTask PublishAsync(T domainEvent, CancellationToken ct)
   134→        {
   135→            try
   136→            {
   137→                await _channel.Writer.WriteAsync(domainEvent, ct).ConfigureAwait(false);
   138→            }
   139→            catch (OperationCanceledException) when (ct.IsCancellationRequested)
   140→            {
   141→                _logger.LogWarning("PublishAsync was cancelled.");
   142→                throw;
   143→            }
   144→        }
   145→
   146→        private async Task PumpAsync(CancellationToken ct)
   147→        {
   148→            await foreach (var item in _channel.Reader.ReadAllAsync(ct).ConfigureAwait(false))
   149→            {
   150→                foreach (var observer in _observers)
   151→                {
   152→                    try
   153→                    {
   154→                        await observer.OnNextAsync(item, ct).ConfigureAwait(false);
   155→                    }
   156→                    catch (Exception ex)
   157→                    {
   158→                        _logger.LogError(ex, "Observer {Observer} failed to process event {Event}.", observer.GetType().Name, item);
   159→                        // Swallow to ensure other observers still receive the event
   160→                    }
   161→                }
   162→            }
   163→        }
   164→
   165→        public void Dispose()
   166→        {
   167→            _internalCts.Cancel();
   168→            _channel.Writer.Complete();
   169→            try { _pumpTask.Wait(TimeSpan.FromSeconds(5)); }
   170→            catch { /* ignored */ }
