   215→            _logger.LogInformation("DeploymentLeadTimeStrategy started. Waiting for cancellation…");
   216→            try
   217→            {
   218→                // Just wait until cancelled. All heavy lifting is event-driven via observers.
   219→                await Task.Delay(Timeout.Infinite, cancellationToken).ConfigureAwait(false);
   220→            }
   221→            catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
   222→            {
   223→                _logger.LogInformation("DeploymentLeadTimeStrategy is shutting down due to cancellation.");
   224→            }
   225→            finally
   226→            {
   227→                Dispose();
   228→            }
   229→        }
   230→
   231→        public async ValueTask OnNextAsync(DomainEvent @event, CancellationToken ct)
   232→        {
   233→            switch (@event)
   234→            {
   235→                case CodeCommitEvent commit:
   236→                    HandleCommit(commit);
   237→                    break;
   238→
   239→                case DeploymentEvent deployment:
   240→                    await HandleDeploymentAsync(deployment, ct).ConfigureAwait(false);
   241→                    break;
   242→
   243→                default:
   244→                    _logger.LogDebug("Ignoring unrelated event type {EventType}.", @event.GetType().Name);
   245→                    break;
   246→            }
   247→        }
