   249→        private void HandleCommit(CodeCommitEvent commit)
   250→        {
   251→            _commitCache[commit.CommitId] = commit;
   252→            _logger.LogTrace("Cached commit {CommitId} ({Repo}) pushed at {Timestamp}.",
   253→                commit.CommitId, commit.Repository, commit.PushedAtUtc);
   254→        }
