   261→                _logger.LogInformation("Deployment for commit {CommitId} received but commit not found in cache. " +
   262→                                        "Lead-time cannot be computed at this moment.", deployment.CommitId);
   263→                return;
   264→            }
   265→
   266→            var leadTime = (deployment.DeployedAtUtc - commit.PushedAtUtc).TotalSeconds;
   267→            if (leadTime < 0)
   268→            {
   269→                _logger.LogWarning("Negative lead-time computed for commit {CommitId}. Pushed at: {Push}, Deployed at: {Deploy}",
   270→                    deployment.CommitId, commit.PushedAtUtc, deployment.DeployedAtUtc);
   271→                // Still record it for further root-cause analysis.
   272→            }
   273→
   274→            var record = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase)
   275→            {
   276→                ["kpi_name"]           = OutputKpiName,
   277→                ["commit_id"]          = deployment.CommitId,
   278→                ["repository"]         = commit.Repository,
   279→                ["environment"]        = deployment.Environment,
   280→                ["author_email"]       = commit.AuthorEmail,
   281→                ["deployed_by"]        = deployment.DeployedBy,
   282→                ["lead_time_seconds"]  = leadTime,
   283→                ["committed_at_utc"]   = commit.PushedAtUtc.ToString("o", CultureInfo.InvariantCulture),
   284→                ["deployed_at_utc"]    = deployment.DeployedAtUtc.ToString("o", CultureInfo.InvariantCulture),
   285→                ["snapshot_date"]      = deployment.DeployedAtUtc.UtcDateTime.Date.ToString("yyyy-MM-dd", CultureInfo.InvariantCulture)
   286→            };
   287→
   288→            if (_sink is null)
   289→            {
   290→                _logger.LogError("Sink has not been initialized. Dropping computed KPI record for commit {CommitId}.",
   291→                    deployment.CommitId);
   292→                return;
   293→            }
   294→
   295→            _logger.LogDebug("Computed deployment lead-time for commit {CommitId}: {LeadTime}s.", deployment.CommitId, leadTime);
   296→
   297→            try
   298→            {
   299→                await _sink.AddAsync(record, ct).ConfigureAwait(false);
   300→            }
   301→            catch (Exception ex)
   302→            {
   303→                _logger.LogError(ex, "Failed to persist lead-time KPI for commit {CommitId}.", deployment.CommitId);
