     2→// -----------------------------------------------------------------------------
     3→// PulseOps Warehouse — Serverless Productivity Intelligence Fabric
     4→// File: src/module_9.cs
     5→//
     6→// Module 9: Dynamic Data-Transformation Engine
     7→//
     8→// Description
     9→// -----------
    10→// Implements the Strategy Pattern to dynamically resolve and execute
    11→// data-transformation algorithms at runtime.  The engine is used by several
    12→// Lambda micro-components (stream, batch, CDC) to convert raw telemetry into
    13→// domain KPIs.  Strategies are resolved through attribute-based discovery and
    14→// wired via Microsoft.Extensions.DependencyInjection so that teams can
    15→// hot-swap business logic without re-deploying the outer Lambda shell.
    16→//
    17→// AWS SSM is used for real-time feature-flag control, enabling Ops to promote
    18→// or roll back strategies instantly.  The engine is thread-safe, highly
    19→// observable, and defensive against poisoned messages.
    20→//
    21→// -----------------------------------------------------------------------------
    22→
    23→using System;
    24→using System.Collections.Concurrent;
    25→using System.Collections.Generic;
    26→using System.Linq;
    27→using System.Reflection;
    28→using System.Text.Json;
    29→using System.Threading;
    30→using System.Threading.Tasks;
    31→using Amazon.SimpleSystemsManagement;
    32→using Amazon.SimpleSystemsManagement.Model;
    33→using Microsoft.Extensions.DependencyInjection;
    34→using Microsoft.Extensions.Logging;
    35→
    36→namespace PulseOps.Warehouse.Transformations
    37→{
    38→    #region Public Contracts
    39→
    40→    /// <summary>
    41→    ///   DTO for an incoming pipeline record.  The envelope contains both the
    42→    ///   raw JSON payload and a set of normalized headers used throughout the
    43→    ///   warehouse mesh.
    44→    /// </summary>
    45→    public sealed record RecordEnvelope(
    46→        string Stream,               // e.g. “prod/github/push”
    47→        string SchemaVersion,        // e.g. “v1”
    48→        DateTimeOffset Timestamp,    // producer timestamp
    49→        JsonDocument Payload)        // opaque JSON blob
    50→    {
    51→        public string TenantId =>
    52→            Payload.RootElement.TryGetProperty("tenantId", out var t)
    53→                ? t.GetString() ?? "unknown"
    54→                : "unknown";
    55→
    56→        /// <summary>Convenience accessor for correlation id.</summary>
    57→        public string CorrelationId =>
    58→            Payload.RootElement.TryGetProperty("correlationId", out var c)
    59→                ? c.GetString() ?? Guid.Empty.ToString()
    60→                : Guid.Empty.ToString();
    61→    }
    62→
    63→    /// <summary>
    64→    ///   Data-transformation strategy abstraction.  Implementations convert a
    65→    ///   <see cref="RecordEnvelope"/> into the derived KPI representation.
    66→    /// </summary>
    67→    public interface IDataTransformationStrategy
    68→    {
    69→        /// <summary>Unique name used during strategy selection (case-insensitive).</summary>
    70→        string Name { get; }
    71→
    72→        /// <summary>Executes the transformation asynchronously.</summary>
    73→        /// <exception cref="TransformationException">
    74→        ///   Thrown when a business-rule violation or unrecoverable data
    75→        ///   inconsistency is detected.
    76→        /// </exception>
    77→        Task<JsonElement> TransformAsync(
    78→            RecordEnvelope envelope,
    79→            CancellationToken cancellationToken = default);
    80→    }
    81→
    82→    /// <summary>
    83→    ///   Marker attribute used for automatic strategy discovery through
    84→    ///   reflection.
    85→    /// </summary>
    86→    [AttributeUsage(AttributeTargets.Class)]
    87→    public sealed class TransformationStrategyAttribute : Attribute
    88→    {
    89→        public TransformationStrategyAttribute(string name)
    90→        {
    91→            Name = name;
    92→        }
    93→
    94→        public string Name { get; }
    95→    }
    96→
    97→    /// <summary>Thrown when transformation processing fails.</summary>
    98→    public sealed class TransformationException : Exception
    99→    {
   100→        public TransformationException(string message, Exception? inner = null)
   101→            : base(message, inner) { }
   102→    }
   103→
   104→    #endregion
   105→
   106→    #region Strategy Resolution & Execution Engine
   107→
   108→    /// <summary>
   109→    ///   Resolves and executes transformation strategies.  The engine supports
   110→    ///   per-tenant overrides by querying AWS SSM Parameter Store for a
   111→    ///   “/pulseops/{tenant}/transformationStrategy” string parameter.
   112→    /// </summary>
   113→    public sealed class DataTransformationEngine
   114→    {
   115→        private const string DefaultStrategyParameter =
   116→            "/pulseops/global/defaultTransformationStrategy";
   117→
   118→        private readonly IServiceProvider _serviceProvider;
   119→        private readonly IAmazonSimpleSystemsManagement _ssm;
   120→        private readonly ILogger<DataTransformationEngine> _logger;
   121→
   122→        // Cache mapping strategy name -> strategy instance
   123→        private readonly ConcurrentDictionary<string, IDataTransformationStrategy>
   124→            _strategyCache = new(StringComparer.OrdinalIgnoreCase);
   125→
   126→        // Cache mapping tenant -> active strategy name
   127→        private readonly ConcurrentDictionary<string, (string StrategyName, DateTimeOffset Expires)>
   128→            _tenantStrategyCache = new(StringComparer.OrdinalIgnoreCase);
   129→
   130→        // TTL for Parameter Store look-ups
   131→        private readonly TimeSpan _parameterTtl = TimeSpan.FromMinutes(5);
   132→
   133→        public DataTransformationEngine(
   134→            IServiceProvider serviceProvider,
   135→            IAmazonSimpleSystemsManagement ssm,
   136→            ILogger<DataTransformationEngine> logger)
   137→        {
   138→            _serviceProvider = serviceProvider;
   139→            _ssm            = ssm;
   140→            _logger         = logger;
   141→        }
   142→
   143→        /// <summary>
   144→        ///   Discovers all strategy types that carry <see cref="TransformationStrategyAttribute"/>
   145→        ///   and registers them with the DI container.  Should be invoked once
   146→        ///   during application startup.
   147→        /// </summary>
   148→        public static void RegisterStrategies(IServiceCollection services, ILogger? bootstrapLogger = null)
   149→        {
   150→            var strategyTypes =
   151→                Assembly.GetExecutingAssembly()
   152→                        .DefinedTypes
   153→                        .Where(t => !t.IsAbstract
   154→                                    && typeof(IDataTransformationStrategy).IsAssignableFrom(t)
   155→                                    && t.GetCustomAttribute<TransformationStrategyAttribute>() is not null)
   156→                        .ToArray();
   157→
   158→            foreach (var type in strategyTypes)
   159→            {
   160→                services.AddSingleton(typeof(IDataTransformationStrategy), type);
   161→                bootstrapLogger?.LogInformation(
   162→                    "Registered transformation strategy {StrategyType}", type.FullName);
   163→            }
   164→        }
   165→
   166→        /// <summary>
   167→        ///   Entry point used by Lambda handler.
   168→        /// </summary>
   169→        public async Task<JsonElement> TransformAsync(
   170→            RecordEnvelope envelope,
   171→            CancellationToken cancellationToken = default)
   172→        {
   173→            if (envelope is null)
   174→                throw new ArgumentNullException(nameof(envelope));
   175→
   176→            var strategy = await ResolveStrategyAsync(envelope.TenantId, cancellationToken);
   177→            try
   178→            {
   179→                return await strategy.TransformAsync(envelope, cancellationToken);
   180→            }
   181→            catch (TransformationException tex)
   182→            {
   183→                // Business-level exception: send to DLQ with context
   184→                _logger.LogWarning(tex,
   185→                    "Transformation failed (tenant={Tenant}, strategy={Strategy})",
   186→                    envelope.TenantId, strategy.Name);
   187→
   188→                throw;
   189→            }
   190→            catch (Exception ex)
   191→            {
   192→                // Unexpected failure
   193→                _logger.LogError(ex,
   194→                    "Unhandled error in transformation engine (tenant={Tenant}, strategy={Strategy})",
   195→                    envelope.TenantId, strategy.Name);
   196→
   197→                throw new TransformationException(
   198→                    $"Unexpected error executing strategy {strategy.Name}", ex);
   199→            }
   200→        }
   201→
   202→        #region Strategy Resolution Internals
   203→
   204→        private async Task<IDataTransformationStrategy> ResolveStrategyAsync(
   205→            string tenant,
   206→            CancellationToken cancellationToken)
   207→        {
   208→            var (strategyName, _) =
   209→                await GetTenantStrategyNameAsync(tenant, cancellationToken);
   210→
   211→            if (_strategyCache.TryGetValue(strategyName, out var strategy))
   212→                return strategy;
   213→
   214→            // Strategy not yet cached, resolve through DI
   215→            strategy = _serviceProvider
   216→                      .GetServices<IDataTransformationStrategy>()
   217→                      .FirstOrDefault(s =>
   218→                          s.Name.Equals(strategyName, StringComparison.OrdinalIgnoreCase));
   219→
   220→            if (strategy is null)
   221→            {
   222→                // Fallback to default & warn
   223→                _logger.LogWarning(
   224→                    "Configured strategy '{Strategy}' not found; falling back to 'Noop'",
   225→                    strategyName);
   226→
   227→                strategy = new NoopTransformationStrategy();
   228→            }
   229→
   230→            _strategyCache[strategyName] = strategy;
   231→            return strategy;
   232→        }
   233→
   234→        private async Task<(string StrategyName, DateTimeOffset Expires)>
   235→            GetTenantStrategyNameAsync(string tenant, CancellationToken token)
   236→        {
   237→            if (_tenantStrategyCache.TryGetValue(tenant, out var entry)
   238→                && entry.Expires > DateTimeOffset.UtcNow)
   239→            {
   240→                return entry;
   241→            }
   242→
   243→            // Compose tenant parameter path
   244→            var parameterName = $"/pulseops/{tenant}/transformationStrategy";
   245→            var defaultUsed   = false;
   246→
   247→            try
   248→            {
   249→                var response = await _ssm.GetParameterAsync(
   250→                    new GetParameterRequest
   251→                    {
   252→                        Name           = parameterName,
   253→                        WithDecryption = false
   254→                    }, token);
   255→
   256→                entry = (response.Parameter.Value, DateTimeOffset.UtcNow + _parameterTtl);
   257→            }
   258→            catch (ParameterNotFoundException)
   259→            {
   260→                // Tenant override missing — use global default
   261→                var response = await _ssm.GetParameterAsync(
   262→                    new GetParameterRequest
   263→                    {
   264→                        Name           = DefaultStrategyParameter,
   265→                        WithDecryption = false
   266→                    }, token);
   267→
   268→                entry       = (response.Parameter.Value, DateTimeOffset.UtcNow + _parameterTtl);
   269→                defaultUsed = true;
   270→            }
   271→
   272→            _tenantStrategyCache[tenant] = entry;
   273→
   274→            if (defaultUsed)
   275→                _logger.LogInformation(
   276→                    "Using default strategy '{Strategy}' for tenant '{Tenant}'",
   277→                    entry.StrategyName, tenant);
   278→            else
   279→                _logger.LogInformation(
   280→                    "Using tenant-specific strategy '{Strategy}' for tenant '{Tenant}'",
   281→                    entry.StrategyName, tenant);
   282→
   283→            return entry;
   284→        }
   285→
   286→        #endregion
   287→    }
   288→
   289→    #endregion
