   291→    #region Built-in Strategies
   292→
   293→    /// <summary>
   294→    ///   Default no-op strategy that simply echos back the original payload.
   295→    ///   Useful for smoke tests or when a tenant chooses to disable KPI
   296→    ///   generation entirely.
   297→    /// </summary>
   298→    [TransformationStrategy("Noop")]
   299→    internal sealed class NoopTransformationStrategy : IDataTransformationStrategy
   300→    {
   301→        public string Name => "Noop";
   302→
   303→        public Task<JsonElement> TransformAsync(
   304→            RecordEnvelope envelope,
   305→            CancellationToken cancellationToken = default)
   306→        {
   307→            // Avoid copying by re-using existing JsonElement
   308→            return Task.FromResult(envelope.Payload.RootElement.Clone());
   309→        }
   310→    }
