   312→    /// <summary>
   313→    ///   Calculates Meeting Cost Index (MCI) based on calendar telemetry.
   314→    ///   The resulting JSON adheres to the KPI v1 schema.
   315→    /// </summary>
   316→    [TransformationStrategy("MeetingCostIndex")]
   317→    internal sealed class MeetingCostIndexStrategy : IDataTransformationStrategy
   318→    {
   319→        public string Name => "MeetingCostIndex";
   320→
   321→        public async Task<JsonElement> TransformAsync(
   322→            RecordEnvelope envelope,
   323→            CancellationToken cancellationToken = default)
   324→        {
   325→            // Simulate I/O latency for demonstration purposes
   326→            await Task.Delay(TimeSpan.FromMilliseconds(15), cancellationToken);
   327→
   328→            var root = envelope.Payload.RootElement;
   329→
   330→            if (!root.TryGetProperty("attendees", out var attendees))
   331→                throw new TransformationException("Payload missing 'attendees' property");
   332→
   333→            if (!root.TryGetProperty("durationMinutes", out var durationProp)
   334→                || !durationProp.TryGetInt32(out var durationMinutes))
   335→                throw new TransformationException("Payload missing or invalid 'durationMinutes'");
   336→
   337→            var totalHourlyCost = attendees.EnumerateArray()
   338→                                           .Select(a => a.GetProperty("hourlyRateUsd").GetDecimal())
   339→                                           .Sum();
   340→
   341→            var cost = totalHourlyCost * (durationMinutes / 60m);
   342→
   343→            using var doc = JsonDocument.Parse($$"""
   344→            {
   345→              "kpi"            : "meetingCostIndex",
   346→              "schemaVersion"  : "v1",
   347→              "tenantId"       : "{{envelope.TenantId}}",
   348→              "correlationId"  : "{{envelope.CorrelationId}}",
   349→              "timestampUtc"   : "{{DateTimeOffset.UtcNow:o}}",
   350→              "payload"        : {
   351→                  "meetingId"       : "{{root.GetProperty("meetingId").GetString()}}",
   352→                  "durationMinutes" : {{durationMinutes}},
   353→                  "attendeeCount"   : {{attendees.GetArrayLength()}},
   354→                  "totalCostUsd"    : {{cost}}
   355→              }
   356→            }
   357→            """);
   358→
   359→            // Materialize JsonElement before disposing doc
   360→            return doc.RootElement.Clone();
   361→        }
   362→    }
