   364→    /// <summary>
   365→    ///   Calculates Focus Time Ratio KPI from IDE + Calendar streams.
   366→    /// </summary>
   367→    [TransformationStrategy("FocusTimeRatio")]
   368→    internal sealed class FocusTimeRatioStrategy : IDataTransformationStrategy
   369→    {
   370→        public string Name => "FocusTimeRatio";
   371→
   372→        public Task<JsonElement> TransformAsync(
   373→            RecordEnvelope envelope,
   374→            CancellationToken cancellationToken = default)
   375→        {
   376→            var root = envelope.Payload.RootElement;
