   223→    /// <summary>
   224→    /// Simple DI-friendly registry for strategies. Acts as a façade for discovery, selection, and execution.
   225→    /// </summary>
   226→    public sealed class TransformationEngine
   227→    {
   228→        private readonly IReadOnlyDictionary<string, ITransformationStrategy> _strategies;
   229→        private readonly ILogger _logger;
   230→
   231→        public TransformationEngine(IEnumerable<ITransformationStrategy> strategies, ILogger<TransformationEngine> logger)
   232→        {
   233→            _strategies = strategies.ToDictionary(s => s.Name, StringComparer.OrdinalIgnoreCase);
   234→            _logger = logger;
   235→        }
   236→
   237→        /// <summary>
   238→        /// Executes a set of strategy names against the provided event stream.
   239→        /// </summary>
   240→        /// <returns>KPI name → result.</returns>
   241→        public async Task<IDictionary<string, KpiResult>> RunAsync(
   242→            IAsyncEnumerable<RawEvent> events,
   243→            IEnumerable<string> strategyNames,
   244→            CancellationToken cancellationToken = default)
   245→        {
   246→            var uniqueNames = strategyNames
   247→                .Select(s => s.Trim())
   248→                .Where(s => !string.IsNullOrWhiteSpace(s))
   249→                .Distinct(StringComparer.OrdinalIgnoreCase)
   250→                .ToList();
   251→
   252→            var missing = uniqueNames.Where(n => !_strategies.ContainsKey(n)).ToList();
   253→            if (missing.Any())
   254→                throw new ArgumentException($"Unknown KPIs requested: {string.Join(", ", missing)}", nameof(strategyNames));
   255→
   256→            // Materialize the source stream once into memory-efficient list to fan-out to multiple strategies,
   257→            // because IAsyncEnumerable can be consumed only once.
   258→            var buffered = await events.ToListAsync(cancellationToken);
   259→
   260→            var tasks = uniqueNames
   261→                .Select(name => ExecuteStrategyAsync(name, buffered, cancellationToken))
   262→                .ToArray();
   263→
   264→            await Task.WhenAll(tasks);
   265→
   266→            return tasks
   267→                .Where(t => t.Result != null)
   268→                .ToDictionary(t => t.Result!.KpiName, t => t.Result!, StringComparer.OrdinalIgnoreCase);
   269→        }
   270→
   271→        private async Task<KpiResult?> ExecuteStrategyAsync(
   272→            string name,
   273→            IReadOnlyList<RawEvent> buffer,
   274→            CancellationToken ct)
   275→        {
   276→            if (!_strategies.TryGetValue(name, out var strategy))
   277→                return null; // Should never happen due to earlier check.
   278→
   279→            try
   280→            {
   281→                _logger.LogDebug("Starting KPI strategy {Name}.", name);
   282→                var sw = Stopwatch.StartNew();
   283→
   284→                // Copy the buffer into an async stream for each strategy.
   285→                async IAsyncEnumerable<RawEvent> Stream()
   286→                {
   287→                    foreach (var ev in buffer)
   288→                    {
   289→                        ct.ThrowIfCancellationRequested();
   290→                        yield return ev;
   291→                    }
   292→                }
   293→
   294→                var result = await strategy.TransformAsync(Stream(), ct);
   295→                _logger.LogDebug("KPI strategy {Name} completed in {ElapsedMs}ms.", name, sw.ElapsedMilliseconds);
   296→                return result;
   297→            }
   298→            catch (OperationCanceledException)
   299→            {
   300→                _logger.LogWarning("KPI strategy {Name} canceled.", name);
   301→                throw;
   302→            }
   303→            catch (Exception ex)
   304→            {
   305→                _logger.LogError(ex, "KPI strategy {Name} failed.", name);
   306→                return null; // Swallow to allow other strategies to continue.
   307→            }
   308→        }
   309→    }
