    15→    /// <summary>
    16→    ///     Calculates the total cost of a calendar meeting based on duration,
    17→    ///     attendee hourly rates, and organizational modifiers (e.g. contractor uplift).
    18→    ///     The result is exposed as <see cref="MeetingCostRecord"/>.
    19→    ///
    20→    ///     This strategy is later aggregated by downstream Lambdas to construct the
    21→    ///     Meeting-Cost-Index KPI across teams, departments, or cost centres.
    22→    /// </summary>
    23→    public sealed class MeetingCostIndexStrategy : ITransformationStrategy<CalendarEventRecord, MeetingCostRecord>
    24→    {
    25→        private readonly IRateCardProvider _rateCardProvider;
    26→        private readonly ILogger<MeetingCostIndexStrategy> _logger;
    27→
    28→        public MeetingCostIndexStrategy(
    29→            IRateCardProvider rateCardProvider,
    30→            ILogger<MeetingCostIndexStrategy> logger)
    31→        {
    32→            _rateCardProvider = rateCardProvider ?? throw new ArgumentNullException(nameof(rateCardProvider));
    33→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
    34→        }
    35→
    36→        /// <inheritdoc/>
    37→        public async Task<MeetingCostRecord?> TransformAsync(
    38→            CalendarEventRecord input,
    39→            CancellationToken cancellationToken = default)
    40→        {
    41→            if (input is null)
    42→            {
    43→                throw new ArgumentNullException(nameof(input));
    44→            }
    45→
    46→            if (!input.Attendees.Any())
    47→            {
    48→                _logger.LogWarning("Calendar event '{EventId}' has no attendees — cost evaluation skipped.",
    49→                                   input.EventId);
    50→                return null;
    51→            }
    52→
    53→            try
    54→            {
    55→                var durationHours = (decimal)(input.EndTimeUtc - input.StartTimeUtc).TotalMinutes / 60m;
    56→                if (durationHours <= 0)
    57→                {
    58→                    _logger.LogWarning("Calendar event '{EventId}' duration is <= 0. Event ignored.", input.EventId);
    59→                    return null;
    60→                }
    61→
    62→                var costByAttendee = new ConcurrentBag<decimal>();
    63→
    64→                // Parallelise rate look-ups for events with hundreds of attendees.
    65→                await Parallel.ForEachAsync(input.Attendees, cancellationToken, async (attendee, ct) =>
    66→                {
    67→                    var hourlyRate = await _rateCardProvider.GetHourlyRateAsync(attendee, ct)
    68→                                                            .ConfigureAwait(false);
    69→
    70→                    costByAttendee.Add(hourlyRate * durationHours);
    71→                });
    72→
    73→                var totalCost = costByAttendee.Sum();
    74→
    75→                var output = new MeetingCostRecord
    76→                {
    77→                    EventId = input.EventId,
    78→                    StartTimeUtc = input.StartTimeUtc,
    79→                    EndTimeUtc = input.EndTimeUtc,
    80→                    CalculatedCost = Math.Round(totalCost, 2, MidpointRounding.AwayFromZero),
    81→                    Currency = _rateCardProvider.CurrencyCode
    82→                };
    83→
    84→                _logger.LogDebug("Calculated meeting cost for '{EventId}': {Cost} {Currency}.",
    85→                                 input.EventId,
    86→                                 output.CalculatedCost.ToString("F2", CultureInfo.InvariantCulture),
    87→                                 output.Currency);
    88→
    89→                return output;
    90→            }
    91→            catch (Exception ex)
    92→            {
    93→                _logger.LogError(ex, "Fatal error while calculating MeetingCostIndex for event '{EventId}'.",
    94→                                 input.EventId);
    95→                throw;
    96→            }
    97→        }
    98→    }
