   195→    /// </summary>
   196→    public sealed class CachedRateCardProvider : IRateCardProvider, IDisposable
   197→    {
   198→        private readonly IMemoryCache _cache;
   199→        private readonly ILogger<CachedRateCardProvider> _logger;
   200→
   201→        // Simulated backing store (would be an async repository in real life)
   202→        private static readonly IDictionary<string, decimal> _hrDatabaseMock = new Dictionary<string, decimal>(StringComparer.OrdinalIgnoreCase)
   203→        {
   204→            ["engineering"] = 95.00m,
   205→            ["product"]     = 85.00m,
   206→            ["sales"]       = 70.00m,
   207→            ["default"]     = 60.00m
   208→        };
   209→
   210→        public CachedRateCardProvider(ILogger<CachedRateCardProvider> logger)
   211→        {
   212→            _cache  = new MemoryCache(new MemoryCacheOptions());
   213→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   214→        }
   215→
   216→        public string CurrencyCode => "USD";
   217→
   218→        /// <inheritdoc/>
   219→        public Task<decimal> GetHourlyRateAsync(Attendee attendee, CancellationToken cancellationToken = default)
   220→        {
   221→            if (attendee is null)
   222→                throw new ArgumentNullException(nameof(attendee));
   223→
   224→            // Normalise cache key (email preferred for uniqueness; fallback to dept)
   225→            var cacheKey = $"rate:{attendee.Email.ToLowerInvariant()}";
   226→
   227→            if (_cache.TryGetValue<decimal>(cacheKey, out var cachedRate))
   228→            {
   229→                return Task.FromResult(cachedRate);
   230→            }
   231→
   232→            // Simulate expensive I/O latency
   233→            return Task.Run(async () =>
   234→            {
   235→                _logger.LogTrace("Fetching hourly rate for {Email} from backing store…", attendee.Email);
   236→
   237→                await Task.Delay(TimeSpan.FromMilliseconds(20), cancellationToken)
   238→                          .ConfigureAwait(false);
   239→
   240→                var baseRate = ResolveRateFromMock(attendee);
   241→                var adjustedRate = attendee.IsContractor ? baseRate * 1.2m : baseRate; // contractor uplift
   242→
   243→                // Cache for 15 minutes with sliding expiration
   244→                _cache.Set(cacheKey, adjustedRate, new MemoryCacheEntryOptions
   245→                {
   246→                    AbsoluteExpirationRelativeToNow = TimeSpan.FromMinutes(15)
   247→                });
   248→
   249→                return adjustedRate;
   250→
   251→            }, cancellationToken);
   252→        }
   253→
   254→        private static decimal ResolveRateFromMock(Attendee attendee)
   255→        {
   256→            if (!string.IsNullOrWhiteSpace(attendee.Department) &&
   257→                _hrDatabaseMock.TryGetValue(attendee.Department, out var deptRate))
   258→            {
   259→                return deptRate;
   260→            }
