   262→            // Fallback by role
   263→            if (!string.IsNullOrWhiteSpace(attendee.Role) &&
   264→                _hrDatabaseMock.TryGetValue(attendee.Role, out var roleRate))
   265→            {
   266→                return roleRate;
   267→            }
   268→
   269→            return _hrDatabaseMock["default"];
   270→        }
