```csharp
    /// <summary>
    /// Provides centralized resilience patterns for asynchronous operations,
    /// implementing exponential backoff retry strategy with configurable parameters.
    /// </summary>
    public static class ResilienceHelper
    {
        /// <summary>
        /// Executes an asynchronous operation with exponential backoff retry logic.
        /// Uses centralized configuration from PulseOpsConstants.
        /// </summary>
        /// <typeparam name="T">The return type of the asynchronous operation.</typeparam>
        /// <param name="operation">The asynchronous operation to execute.</param>
        /// <param name="cancellationToken">Optional cancellation token for cooperative cancellation.</param>
        /// <returns>The result of the successful operation.</returns>
        /// <exception cref="Exception">
        /// Re-throws the last exception if all retry attempts are exhausted.
        /// </exception>
        public static async Task<T> ExecuteWithRetryAsync<T>(
            Func<Task<T>> operation,
            CancellationToken cancellationToken = default)
        {
            var maxRetries = PulseOps.Warehouse.Shared.PulseOpsConstants.API_MAX_RETRIES;
            var initialBackoffMs = PulseOps.Warehouse.Shared.PulseOpsConstants.API_INITIAL_BACKOFF_MS;

            Exception? lastException = null;

            for (int attempt = 0; attempt <= maxRetries; attempt++)
            {
                try
                {
                    cancellationToken.ThrowIfCancellationRequested();
                    return await operation().ConfigureAwait(false);
                }
                catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
                {
                    // Don't retry on cancellation - propagate immediately
                    throw;
                }
                catch (Exception ex) when (IsTransientException(ex) && attempt < maxRetries)
                {
                    lastException = ex;

                    // Calculate exponential backoff delay: initialBackoff * 2^attempt
                    var delayMs = initialBackoffMs * (int)Math.Pow(2, attempt);

                    await Task.Delay(delayMs, cancellationToken).ConfigureAwait(false);
                }
                catch (Exception ex)
                {
                    // Non-transient exception or max retries exceeded
                    lastException = ex;
                    throw;
                }
            }

            // Should not reach here, but throw last exception if we somehow do
            throw lastException ?? new InvalidOperationException("Retry logic exhausted without capturing an exception.");
        }

        /// <summary>
        /// Overload for operations that don't return a value.
        /// </summary>
        public static async Task ExecuteWithRetryAsync(
            Func<Task> operation,
            CancellationToken cancellationToken = default)
        {
            await ExecuteWithRetryAsync(async () =>
            {
                await operation().ConfigureAwait(false);
                return true; // Dummy return value
            }, cancellationToken).ConfigureAwait(false);
        }

        /// <summary>
        /// Determines if an exception is transient and should trigger a retry.
        /// </summary>
        private static bool IsTransientException(Exception ex)
        {
            return ex switch
            {
                // HTTP client transient errors
                System.Net.Http.HttpRequestException => true,

                // Timeout errors
                TimeoutException => true,

                // Web exceptions (legacy)
                WebException => true,

                // AWS SDK errors with transient status codes
                Amazon.Runtime.AmazonServiceException ase
                    when ase.StatusCode is HttpStatusCode.TooManyRequests
                                        or HttpStatusCode.InternalServerError
                                        or HttpStatusCode.BadGateway
                                        or HttpStatusCode.ServiceUnavailable
                                        or HttpStatusCode.GatewayTimeout
                    => true,

                // S3-specific transient errors
                Amazon.S3.AmazonS3Exception s3Ex
                    when (int)s3Ex.StatusCode >= 500
                    => true,

                _ => false
            };
        }
    }
```

